I need to add a 'list active orders for a customer, sorted by date desc, paged' endpoint. Here's what I have. Anything wrong with this approach? Show me how it should look.

```csharp
public class OrderAppService : ApplicationService, IOrderAppService
{
    private readonly IRepository<Order, Guid> _orderRepository;

    public OrderAppService(IRepository<Order, Guid> orderRepository)
    {
        _orderRepository = orderRepository;
    }

    public async Task<PagedResultDto<OrderDto>> GetActiveForCustomerAsync(
        Guid customerId, int skipCount, int maxResultCount)
    {
        var queryable = await _orderRepository.GetQueryableAsync();
        var query = queryable
            .Where(o => o.CustomerId == customerId && o.Status == OrderStatus.Active)
            .OrderByDescending(o => o.CreationTime);

        var totalCount = await AsyncExecuter.CountAsync(query);
        var orders = await AsyncExecuter.ToListAsync(query.Skip(skipCount).Take(maxResultCount));

        return new PagedResultDto<OrderDto>(
            totalCount,
            ObjectMapper.Map<List<Order>, List<OrderDto>>(orders));
    }
}
